@use "../utilities/css-variables" as cv;
@use "../utilities/initial-variables" as iv;
@use "../utilities/extends";
@use "../utilities/mixins" as mx;

$level-item-spacing: calc(#{cv.getVar("block-spacing")} * 0.5) !default;

.#{iv.$class-prefix}level {
  @extend %block;
  @include cv.register-var("level-item-spacing", #{$level-item-spacing});
  align-items: center;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  gap: cv.getVar("level-item-spacing");

  code {
    border-radius: cv.getVar("radius");
  }

  img {
    display: inline-block;
    vertical-align: top;
  }

  // Modifiers
  &.#{iv.$class-prefix}is-mobile {
    display: flex;
    flex-direction: row;

    .#{iv.$class-prefix}level-left,
    .#{iv.$class-prefix}level-right {
      display: flex;
    }

    .#{iv.$class-prefix}level-item {
      &:not(.#{iv.$class-prefix}is-narrow) {
        flex-grow: 1;
      }
    }
  }

  // Responsiveness
  @include mx.tablet {
    display: flex;
    flex-direction: row;

    & > .#{iv.$class-prefix}level-item {
      &:not(.#{iv.$class-prefix}is-narrow) {
        flex-grow: 1;
      }
    }
  }
}

.#{iv.$class-prefix}level-item {
  align-items: center;
  display: flex;
  flex-basis: auto;
  flex-grow: 0;
  flex-shrink: 0;
  justify-content: center;

  .#{iv.$class-prefix}title,
  .#{iv.$class-prefix}subtitle {
    margin-bottom: 0;
  }
}

.#{iv.$class-prefix}level-left,
.#{iv.$class-prefix}level-right {
  flex-basis: auto;
  flex-grow: 0;
  flex-shrink: 0;
  gap: $level-item-spacing;

  .#{iv.$class-prefix}level-item {
    // Modifiers
    &.#{iv.$class-prefix}is-flexible {
      flex-grow: 1;
    }
  }
}

.#{iv.$class-prefix}level-left {
  align-items: center;
  display: flex;
  flex-direction: column;
  justify-content: flex-start;

  // Responsiveness
  @include mx.tablet {
    flex-direction: row;
  }
}

.#{iv.$class-prefix}level-right {
  align-items: center;
  display: flex;
  flex-direction: column;
  justify-content: flex-end;

  // Responsiveness
  @include mx.tablet {
    flex-direction: row;
  }
}

@use "../utilities/css-variables" as cv;
@use "../utilities/initial-variables" as iv;
@use "../utilities/mixins" as mx;
@use "../utilities/extends";

$skeleton-background: cv.getVar("border") !default;
$skeleton-radius: cv.getVar("radius-small") !default;
$skeleton-block-min-height: 4.5em !default;
$skeleton-lines-gap: 0.75em !default;
$skeleton-line-height: 0.75em !default;

#{iv.$variables-host} {
  @include cv.register-vars(
    (
      "skeleton-background": #{$skeleton-background},
      "skeleton-radius": #{$skeleton-radius},
      "skeleton-block-min-height": #{$skeleton-block-min-height},
      "skeleton-lines-gap": #{$skeleton-lines-gap},
      "skeleton-line-height": #{$skeleton-line-height},
    )
  );
}

%skeleton-pulsation {
  animation-duration: 2s;
  animation-iteration-count: infinite;
  animation-name: pulsate;
  animation-timing-function: cubic-bezier(0.4, 0, 0.6, 1);
  background-color: cv.getVar("skeleton-background");
  border-radius: cv.getVar("skeleton-radius");
  box-shadow: none;
  pointer-events: none;
}

.#{iv.$class-prefix}is-skeleton {
  @extend %skeleton-pulsation;
  color: transparent !important;

  em,
  strong {
    color: inherit;
  }

  img {
    visibility: hidden;
  }

  &.#{iv.$class-prefix}checkbox {
    input {
      opacity: 0;
    }
  }

  &.#{iv.$class-prefix}delete {
    border-radius: cv.getVar("radius-rounded");

    &::before,
    &::after {
      display: none;
    }
  }
}

input.#{iv.$class-prefix}is-skeleton,
textarea.#{iv.$class-prefix}is-skeleton {
  resize: none;

  @include mx.placeholder {
    color: transparent !important;
  }
}

.#{iv.$class-prefix}has-skeleton {
  color: transparent !important;
  position: relative;

  &::after {
    @extend %skeleton-pulsation;
    content: "";
    display: block;
    height: 100%;
    left: 0;
    max-width: 100%;
    min-width: 10%;
    position: absolute;
    top: 0;
    width: 7em;
  }
}

.#{iv.$class-prefix}skeleton-block {
  @extend %block;
  @extend %skeleton-pulsation;
  color: transparent !important;
  min-height: cv.getVar("skeleton-block-min-height");
}

.#{iv.$class-prefix}skeleton-lines {
  color: transparent !important;
  display: flex;
  flex-direction: column;
  gap: cv.getVar("skeleton-lines-gap");
  position: relative;

  > div {
    @extend %skeleton-pulsation;
    height: cv.getVar("skeleton-line-height");

    &:last-child {
      min-width: 4em;
      width: 30%;
    }
  }
}

//
// Pages: Login & Register
//

.login-logo,
.register-logo {
  margin-bottom: .9rem;
  font-size: 2.1rem;
  font-weight: 300;
  text-align: center;

  a {
    color: var(--#{$prefix}secondary-color);
    text-decoration: none;
  }
}

.login-page,
.register-page {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
}

.login-box,
.register-box {
  width: 400px;

  @media (max-width: map-get($grid-breakpoints, sm)) {
    width: 90%;
    margin-top: .5rem;
  }

  .card {
    margin-bottom: 0;
  }
}

.login-card-body,
.register-card-body {
  padding: 20px;
  color: var(--#{$prefix}secondary-color);
  background-color: var(--#{$prefix}body-bg);
  border-top: 0;

  .input-group {
    .form-control {
      &:focus {
        box-shadow: none;

        ~ .input-group-prepend .input-group-text,
        ~ .input-group-append .input-group-text {
          border-color: $input-focus-border-color;
        }
      }

      &.is-valid {
        &:focus {
          box-shadow: none;
        }

        ~ .input-group-prepend .input-group-text,
        ~ .input-group-append .input-group-text {
          border-color: $success;
        }
      }

      &.is-invalid {
        &:focus {
          box-shadow: none;
        }

        ~ .input-group-append .input-group-text {
          border-color: $danger;
        }
      }
    }

    .input-group-text {
      color: var(--#{$prefix}secondary-color);
      background-color: transparent;
      @include border-top-end-radius($border-radius);
      @include border-bottom-end-radius($border-radius);
      @include transition($input-transition);
    }
  }
}

.login-box-msg,
.register-box-msg {
  padding: 0 20px 20px;
  margin: 0;
  text-align: center;
}

.social-auth-links {
  margin: 10px 0;
}

@use '../../sass/variables' as *;

select.browser-default {
  opacity: 1;
  color: var(--md-sys-color-on-background);
}

// TODO: Change to ".select" and not use tag name directly
// Keep selects useable without javascript

select {
  background-color: var(--md-sys-color-surface);
  width: 100%;
  padding: 5px;
  border: 1px solid var(--md-sys-color-outline-variant);
  border-radius: 2px;
  height: 3rem;
}

.select-wrapper:focus-within {
  outline: 2px solid var(--md-sys-color-primary);
  border-radius: 4px;
}

.select-wrapper {
  position: relative;

  .caret {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    margin: auto 0;
    z-index: 0;
    fill: var(--md-sys-color-on-background);
    pointer-events: none;
  }

  // Hide select with overflow hidden instead of using display none
  // (this prevents form validation errors with hidden form elements)
  .hide-select {
    width: 0;
    height: 0;
    overflow: hidden;
    position: absolute;
    top: 0;
    z-index: -1;
  }
}

select:disabled {
  color: var(--md-sys-color-on-surface);
}

.select-wrapper.disabled {
  + label {
    color: var(--md-sys-color-on-surface);
  }
  .caret {
    fill: var(--md-sys-color-on-surface);
  }
}

.select-wrapper input.select-dropdown:disabled {
  color: var(--md-sys-color-on-surface);
  cursor: default;
  user-select: none;
}

.select-wrapper i {
  color: var(--md-sys-color-on-surface);
}

.select-dropdown li.disabled,
.select-dropdown li.disabled > span,
.select-dropdown li.optgroup {
  color: var(--md-sys-color-on-surface);
  //background-color: transparent;
}

// Icons
.select-dropdown li {
  img {
    height: $dropdown-item-height - 10;
    width: $dropdown-item-height - 10;
    margin: 5px 15px;
    object-fit: cover;
    float: right;
  }
}

// Optgroup styles
.select-dropdown li.optgroup {
  border-top: 1px solid rgba(0, 0, 0, 0.04);
  &.selected > span {
    color: var(--md-sys-color-on-background);
  }
  & > span {
    color: var(--md-sys-color-on-surface-variant);
  }
  & ~ li.optgroup-option {
    padding-left: 1rem;
  }
}

// Button group
//
// A button group is a series of buttons laid out next to each other, all part
// of one visual button, but separated by rules to be separate.

.BtnGroup {
  display: inline-block;
  vertical-align: middle;

  @include clearfix();

  // Proper spacing for multiple button groups (a la, gollum editor)
  + .BtnGroup,
  + .btn {
    margin-left: var(--base-size-4);
  }
}

.BtnGroup-item {
  position: relative;
  float: left;
  border-right-width: 0;
  border-radius: 0;

  &:first-child {
    // stylelint-disable-next-line primer/borders
    border-top-left-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-left-radius: $border-radius;
  }

  &:last-child {
    // stylelint-disable-next-line primer/borders
    border-right-width: $border-width;
    // stylelint-disable-next-line primer/borders
    border-top-right-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-right-radius: $border-radius;
  }

  &.selected,
  &[aria-selected='true'],
  &:focus,
  &:active,
  &:hover {
    // stylelint-disable-next-line primer/borders
    border-right-width: $border-width;

    + .BtnGroup-item,
    + .BtnGroup-parent .BtnGroup-item {
      border-left-width: 0;
    }
  }
}

.BtnGroup-parent {
  float: left;

  &:first-child .BtnGroup-item {
    // stylelint-disable-next-line primer/borders
    border-top-left-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-left-radius: $border-radius;
  }

  &:last-child .BtnGroup-item {
    // stylelint-disable-next-line primer/borders
    border-right-width: $border-width;
    // stylelint-disable-next-line primer/borders
    border-top-right-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-right-radius: $border-radius;
  }

  .BtnGroup-item {
    border-right-width: 0;
    border-radius: 0;
  }

  &.selected,
  &[aria-selected='true'],
  &:focus,
  &:active,
  &:hover {
    .BtnGroup-item {
      // stylelint-disable-next-line primer/borders
      border-right-width: $border-width;
    }

    + .BtnGroup-item,
    + .BtnGroup-parent .BtnGroup-item {
      border-left-width: 0;
    }
  }
}

// ensure that the focus ring sits above the adjacent buttons
.BtnGroup-item,
.BtnGroup-parent {
  &:focus,
  &:active {
    z-index: 1;
  }
}

// Select
//
// Replaces the browser default select with a custom one, mostly pulled from
// https://primer.github.io/.

.form-select {
  --#{$prefix}form-select-bg-img: #{escape-svg($form-select-indicator)};

  display: block;
  width: 100%;
  padding: $form-select-padding-y $form-select-indicator-padding $form-select-padding-y $form-select-padding-x;
  font-family: $form-select-font-family;
  @include font-size($form-select-font-size);
  font-weight: $form-select-font-weight;
  line-height: $form-select-line-height;
  color: $form-select-color;
  appearance: none;
  background-color: $form-select-bg;
  background-image: var(--#{$prefix}form-select-bg-img), var(--#{$prefix}form-select-bg-icon, none);
  background-repeat: no-repeat;
  background-position: $form-select-bg-position;
  background-size: $form-select-bg-size;
  border: $form-select-border-width solid $form-select-border-color;
  @include border-radius($form-select-border-radius, 0);
  @include box-shadow($form-select-box-shadow);
  @include transition($form-select-transition);

  &:focus {
    border-color: $form-select-focus-border-color;
    outline: 0;
    @if $enable-shadows {
      @include box-shadow($form-select-box-shadow, $form-select-focus-box-shadow);
    } @else {
      // Avoid using mixin so we can pass custom focus shadow properly
      box-shadow: $form-select-focus-box-shadow;
    }
  }

  &[multiple],
  &[size]:not([size="1"]) {
    padding-right: $form-select-padding-x;
    background-image: none;
  }

  &:disabled {
    color: $form-select-disabled-color;
    background-color: $form-select-disabled-bg;
    border-color: $form-select-disabled-border-color;
  }

  // Remove outline from select box in FF
  &:-moz-focusring {
    color: transparent;
    text-shadow: 0 0 0 $form-select-color;
  }
}

.form-select-sm {
  padding-top: $form-select-padding-y-sm;
  padding-bottom: $form-select-padding-y-sm;
  padding-left: $form-select-padding-x-sm;
  @include font-size($form-select-font-size-sm);
  @include border-radius($form-select-border-radius-sm);
}

.form-select-lg {
  padding-top: $form-select-padding-y-lg;
  padding-bottom: $form-select-padding-y-lg;
  padding-left: $form-select-padding-x-lg;
  @include font-size($form-select-font-size-lg);
  @include border-radius($form-select-border-radius-lg);
}

@if $enable-dark-mode {
  @include color-mode(dark) {
    .form-select {
      --#{$prefix}form-select-bg-img: #{escape-svg($form-select-indicator-dark)};
    }
  }
}

@use "uswds-core" as *;

$collection-thumb-width: 10;
$collection-thumb-width-mobile: 8;
$collection-thumb-margin: 2;

