// stylelint-disable selector-max-type, selector-max-specificity, max-nesting-depth, selector-no-qualifying-type

.details-overlay[open] > summary::before {
  position: fixed;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  z-index: 80;
  display: block;
  cursor: default;
  content: ' ';
  background: transparent;
}

.details-overlay-dark[open] > summary::before {
  z-index: 111;
  background: var(--overlay-backdrop-bgColor, var(--color-primer-canvas-backdrop));
}

.details-reset {
  // Remove marker added by the display: list-item browser default
  > summary {
    list-style: none;
    transition: 80ms cubic-bezier(0.33, 1, 0.68, 1);
    transition-property: color, background-color, box-shadow, border-color;
    // fallback :focus state
    &:focus {
      @include focusOutline;

      // remove fallback :focus if :focus-visible is supported
      &:not(:focus-visible) {
        outline: solid 1px transparent;
      }
    }

    // default focus state
    &:focus-visible {
      @include focusOutline;
    }

    &.btn-primary {
      // fallback :focus state
      &:focus {
        @include focusOutlineOnEmphasis;

        // remove fallback :focus if :focus-visible is supported
        &:not(:focus-visible) {
          outline: solid 1px transparent;
          box-shadow: none;
        }
      }

      // default focus state
      &:focus-visible {
        @include focusOutlineOnEmphasis;
      }
    }
  }
  // Remove marker added by details polyfill
  > summary::before {
    display: none;
  }
  // Remove marker added by Chrome
  > summary::-webkit-details-marker {
    display: none;
  }
}

.details-overlay > summary {
  transition: 80ms cubic-bezier(0.33, 1, 0.68, 1);
  transition-property: color, background-color, box-shadow, border-color;
  // fallback :focus state
  &:focus {
    @include focusOutline;

    // remove fallback :focus if :focus-visible is supported
    &:not(:focus-visible) {
      outline: solid 1px transparent;
    }
  }

  // default focus state
  &:focus-visible {
    @include focusOutline;
  }

  &.btn-primary {
    // fallback :focus state
    &:focus {
      @include focusOutlineOnEmphasis;

      // remove fallback :focus if :focus-visible is supported
      &:not(:focus-visible) {
        outline: solid 1px transparent;
        box-shadow: none;
      }
    }

    // default focus state
    &:focus-visible {
      @include focusOutlineOnEmphasis;
    }
  }
}

@import "../../../scss";

// font-size property with `px` unit
.selector-1 {
  width: 300px;
  background-color: #f00;
  @include font-size(32px);
}

// font-size property with `rem` unit
.selector-2 {
  @include font-size(2rem);
}

// font-size property with !important
.selector-3 {
  @include font-size(2rem !important);
}

// rfs shorthand
.selector-4 {
  @include rfs(2rem);
}

// not supported unit
.selector-5 {
  @include font-size(2em);
}

// special value
.selector-6 {
  @include font-size(inherit);
}

// font-size property inside @support-query
@supports (display: flex) {
  .selector-7 {
    @include rfs(28px);
  }
}

// flex property with unitless values
.selector-8 {
  @include rfs(0 999 32rem, flex);
}

// padding property
.selector-9 {
  @include rfs(2rem, $property: padding);
}

// padding shorthands
.selector-10 {
  @include padding(2rem);
}

.selector-11 {
  @include padding-top(2rem);
}

.selector-12 {
  @include padding-right(2rem);
}

.selector-13 {
  @include padding-bottom(2rem);
}

.selector-14 {
  @include padding-left(2rem);
}

// margin shorthands
.selector-15 {
  @include margin(2rem);
}

.selector-16 {
  @include margin-top(2rem);
}

.selector-17 {
  @include margin-right(2rem);
}

.selector-18 {
  @include margin-bottom(2rem);
}

.selector-19 {
  @include margin-left(2rem);
}

// Multiple values
.selector-20 {
  @include margin(2rem 3rem);
}

// Multiple values with important
.selector-21 {
  @include margin(2rem 3rem !important);
}

// Zero test
.selector-22 {
  @include rfs(0);
}

// Zero combination test
.selector-23 {
  @include margin(0 3rem);
}

// Value with comma
.selector-24 {
  @include rfs(0 0 2rem #f00 #{","} 0 0 3rem #0f0, box-shadow);
}

// Custom properties
.selector-25 {
  @include rfs(3rem, --value);
}

// Test small value
.selector-26 {
  @include font-size(10px);
}

// Negative units
.selector-27 {
  @include margin(-3rem);
}

// Small negative unit
.selector-28 {
  @include margin(-.5rem);
}
